In that case, you can use a separate cache for each index file. Here's a simple example in Python:

```python
import os
import pickle

class IndexCache:
    def __init__(self, index_file):
        self.index_file = index_file
        self.cache_file = index_file + '.cache'
        self.cache = self.load_cache()

    def load_cache(self):
        if os.path.exists(self.cache_file):
            with open(self.cache_file, 'rb') as f:
                return pickle.load(f)
        else:
            return {}

    def save_cache(self):
        with open(self.cache_file, 'wb') as f:
            pickle.dump(self.cache, f)

    def get(self, key):
        return self.cache.get(key)

    def set(self, key, value):
        self.cache[key] = value
        self.save_cache()

    def delete(self, key):
        if key in self.cache:
            del self.cache[key]
            self.save_cache()

    def clear(self):
        self.cache = {}
        self.save_cache()
